cleanup_terminal_theme() {
  local zshrc_path="$TARGET_HOME/.zshrc"

  run_privileged rm -rf "$TARGET_HOME/.oh-my-zsh" "$TARGET_HOME/.poshthemes" "$TARGET_HOME/ohmyzsh"
  run_privileged rm -f "$TARGET_HOME/.local/bin/oh-my-posh"

  if [ -f "$zshrc_path" ]; then
    run_privileged sed -i '/oh-my-posh init zsh/d' "$zshrc_path"
    run_privileged sed -i '/export PATH=\$PATH:\$HOME\/.local\/bin/d' "$zshrc_path"
    set_file_owner "$zshrc_path" "$TARGET_USER"
  fi
}

configure_target_zshrc() {
  local zshrc_path="$TARGET_HOME/.zshrc"

  if [ ! -f "$zshrc_path" ]; then
    return 1
  fi

  if grep -q '^plugins=' "$zshrc_path"; then
    run_privileged sed -i 's/^plugins=.*/plugins=(git zsh-autosuggestions zsh-syntax-highlighting)/' "$zshrc_path"
  else
    printf '%s\n' 'plugins=(git zsh-autosuggestions zsh-syntax-highlighting)' | run_privileged tee -a "$zshrc_path" >/dev/null
  fi

  if run_privileged grep -q '^#\s*DISABLE_MAGIC_FUNCTIONS="true"$' "$zshrc_path"; then
    run_privileged sed -i 's/^#\s*DISABLE_MAGIC_FUNCTIONS="true"$/DISABLE_MAGIC_FUNCTIONS="true"/' "$zshrc_path"
  elif ! run_privileged grep -q '^DISABLE_MAGIC_FUNCTIONS="true"$' "$zshrc_path"; then
    printf '%s\n' 'DISABLE_MAGIC_FUNCTIONS="true"' | run_privileged tee -a "$zshrc_path" >/dev/null
  fi

  set_file_owner "$zshrc_path" "$TARGET_USER"
}

ensure_oh_my_posh_initialized() {
  local zshrc_path="$TARGET_HOME/.zshrc"
  local init_line='eval "$(oh-my-posh init zsh --config ~/.poshthemes/craver.omp.json)"'
  local path_line='export PATH=$PATH:$HOME/.local/bin'

  if [ ! -f "$zshrc_path" ]; then
    return 1
  fi

  if ! grep -Fxq "$path_line" "$zshrc_path"; then
    printf '%s\n' "$path_line" | run_privileged tee -a "$zshrc_path" >/dev/null
  fi

  if ! grep -Fxq "$init_line" "$zshrc_path"; then
    printf '%s\n' "$init_line" | run_privileged tee -a "$zshrc_path" >/dev/null
  fi

  set_file_owner "$zshrc_path" "$TARGET_USER"
}

install_oh_my_posh_for_target() {
  local target_bin_dir="$TARGET_HOME/.local/bin"
  local theme_dir="$TARGET_HOME/.poshthemes"
  local theme_zip="$theme_dir/themes.zip"

  ensure_dir "$target_bin_dir" "$TARGET_USER"
  ensure_dir "$theme_dir" "$TARGET_USER"

  if [ "$github_repo" = "github.com" ]; then
    run_as_target_user "mkdir -p ~/.local/bin && curl -fsSL https://ohmyposh.dev/install.sh | bash -s -- -d ~/.local/bin"
  else
    download_to "https://$github_release/JanDeDobbeleer/oh-my-posh/releases/latest/download/posh-linux-amd64" "$target_bin_dir/oh-my-posh" || return 1
    run_privileged chmod +x "$target_bin_dir/oh-my-posh"
    set_file_owner "$target_bin_dir/oh-my-posh" "$TARGET_USER"
  fi

  download_to "https://$github_release/JanDeDobbeleer/oh-my-posh/releases/latest/download/themes.zip" "$theme_zip" || return 1
  run_privileged unzip -oq "$theme_zip" -d "$theme_dir" || return 1
  run_privileged chmod u+rw "$theme_dir"/*.omp.*
  run_privileged rm -f "$theme_zip"
  run_privileged chown -R "$TARGET_USER:$(target_group)" "$theme_dir"

  ensure_oh_my_posh_initialized || return 1
}

term_config() {
  local oh_my_zsh_dir="$TARGET_HOME/.oh-my-zsh"
  local oh_my_zsh_source
  local oh_my_zsh_repo
  local zsh_path

  print_section "配置终端"

  if [ ! -d "$oh_my_zsh_dir" ]; then
    log "oh-my-zsh 未安装"
    run_privileged rm -rf "$oh_my_zsh_dir" "$TARGET_HOME/.zshrc" "$TARGET_HOME/ohmyzsh"

    run_privileged apt-get update -y || return 1
    run_privileged apt-get install -y zsh || return 1

    oh_my_zsh_source="$(resolve_oh_my_zsh_source)" || return 1
    case "$oh_my_zsh_source" in
      github)
        oh_my_zsh_repo="https://github.com/ohmyzsh/ohmyzsh.git"
        ;;
      *)
        oh_my_zsh_repo="https://mirrors.tuna.tsinghua.edu.cn/git/ohmyzsh.git"
        ;;
    esac

    run_as_target_user "rm -rf ~/ohmyzsh && git clone $(shell_quote "$oh_my_zsh_repo") ~/ohmyzsh && cd ~/ohmyzsh/tools && RUNZSH=no REMOTE=$(shell_quote "$oh_my_zsh_repo") sh install.sh" || return 1
    run_as_target_user "git clone https://$github_repo/zsh-users/zsh-autosuggestions ~/.oh-my-zsh/custom/plugins/zsh-autosuggestions" || true
    run_as_target_user "git clone https://$github_repo/zsh-users/zsh-syntax-highlighting.git ~/.oh-my-zsh/custom/plugins/zsh-syntax-highlighting" || true

    configure_target_zshrc || return 1

    zsh_path="$(command -v zsh)"
    if [ -n "$zsh_path" ]; then
      if [ "$(id -un)" = "$TARGET_USER" ]; then
        chsh -s "$zsh_path" || true
      else
        run_privileged chsh -s "$zsh_path" "$TARGET_USER" || true
      fi
    fi

    if [ ! -x "$TARGET_HOME/.local/bin/oh-my-posh" ]; then
      log "oh-my-posh 未安装"
      if prompt_yes_no_default_yes "是否安装 oh-my-posh?"; then
        install_oh_my_posh_for_target || return 1
      fi
    else
      if prompt_yes_no_default_yes "已安装 oh-my-posh, 是否卸载?"; then
        cleanup_terminal_theme
      fi
    fi
  else
    if prompt_yes_no_default_yes "已安装 oh-my-zsh, 是否卸载 oh-my-zsh 和 oh-my-posh ?"; then
      if [ -x "$oh_my_zsh_dir/tools/uninstall.sh" ]; then
        run_as_target_user "~/.oh-my-zsh/tools/uninstall.sh" || true
      fi
      cleanup_terminal_theme
    fi
  fi
}

register_module "term_config" "term_config" "配置终端" "term_config"

APP_KEYS=("mw" "bt" "1pctl" "kubesphere")
APP_INFOS=("一款简单Linux面板服务" "aaPanel面板（宝塔国外版）" "现代化、开源的 Linux 服务器运维管理面板" "在 Kubernetes 之上构建的面向云原生应用的分布式操作系统")

print_installed_apps() {
  local i

  log "已安装的自选软件:"
  for i in "${!APP_KEYS[@]}"; do
    case "${APP_KEYS[$i]}" in
      mw|bt|1pctl)
        if command_exists "${APP_KEYS[$i]}"; then
          log "${APP_INFOS[$i]} 已安装"
        fi
        ;;
    esac
  done
}

render_app_menu() {
  local i

  for i in "${!APP_KEYS[@]}"; do
    printf "%2s. %-20s%s\n" "$i" "${APP_KEYS[$i]}" "${APP_INFOS[$i]}"
  done
}

install_selected_app() {
  local selection="$1"
  local script_path

  case "$selection" in
    0)
      run_remote_script "https://$github_raw/midoks/mdserver-web/master/scripts/install.sh"
      ;;
    1)
      script_path="$DOWNLOAD_DIR/install_panel.sh"
      download_to "https://download.bt.cn/install/install_panel.sh" "$script_path" || return 1
      bash "$script_path" ed8484bec
      ;;
    2)
      run_remote_script "https://resource.fit2cloud.com/1panel/package/v2/quick_start.sh"
      ;;
    3)
      run_privileged apt-get -y install socat conntrack ebtables ipset || return 1
      (
        cd "$DOWNLOAD_DIR" || exit 1
        download_to_stdout "https://get-kk.kubesphere.io" | sh -
      ) || return 1
      run_privileged chmod +x "$DOWNLOAD_DIR/kk"
      "$DOWNLOAD_DIR/kk" create cluster --with-kubernetes v1.24.14 --container-manager containerd --with-kubesphere v3.4.0
      ;;
    *)
      log "错误选项：$selection"
      ;;
  esac
}

remove_selected_app() {
  local selection="$1"
  local script_path

  case "$selection" in
    0)
      script_path="$DOWNLOAD_DIR/mdserver-uninstall.sh"
      download_to "https://raw.githubusercontent.com/midoks/mdserver-web/master/scripts/uninstall.sh" "$script_path" || return 1
      bash "$script_path"
      ;;
    1)
      script_path="$DOWNLOAD_DIR/bt-uninstall.sh"
      download_to "http://download.bt.cn/install/bt-uninstall.sh" "$script_path" || return 1
      sh "$script_path"
      ;;
    2)
      1pctl uninstall
      ;;
    [qQ])
      return 0
      ;;
    *)
      log "错误选项：$selection"
      ;;
  esac
}

app_install() {
  print_section "自选软件安装"

  while true; do
    echo
    print_installed_apps
    echo
    render_app_menu
    read -r -p "选择需要安装的软件序号 (q:退出): " input

    case "$input" in
      [qQ])
        break
        ;;
      *)
        install_selected_app "$input"
        ;;
    esac
  done
}

app_remove() {
  print_section "自选软件卸载"

  while true; do
    echo
    print_installed_apps
    echo
    render_app_menu
    read -r -p "选择需要卸载的软件序号 (q:退出): " input

    case "$input" in
      [qQ])
        break
        ;;
      *)
        remove_selected_app "$input"
        ;;
    esac
  done
}

register_module "app_install" "app_install" "自选软件安装" "app_install"
register_module "app_remove" "app_remove" "自选软件卸载" "app_remove"

volta_home() {
  printf '%s/.volta\n' "$TARGET_HOME"
}

volta_bin_path() {
  printf '%s/bin/volta\n' "$(volta_home)"
}

target_login_shell() {
  getent passwd "$TARGET_USER" | cut -d: -f7
}

run_with_volta() {
  local command_text="$1"
  run_as_target_user "export VOLTA_HOME=\$HOME/.volta; export PATH=\$VOLTA_HOME/bin:\$PATH; $command_text"
}

volta_command_exists() {
  local command_name="$1"
  run_with_volta "command -v $(shell_quote "$command_name") >/dev/null 2>&1"
}

volta_tool_version() {
  local command_name="$1"
  local version_text

  version_text="$(run_with_volta "$command_name --version" 2>/dev/null | head -n 1 || true)"
  if [ -z "$version_text" ]; then
    version_text="$(run_with_volta "$command_name -V" 2>/dev/null | head -n 1 || true)"
  fi
  if [ -z "$version_text" ]; then
    version_text="$(run_with_volta "$command_name version" 2>/dev/null | head -n 1 || true)"
  fi

  printf '%s\n' "$version_text"
}

ensure_volta_installed() {
  local current_version
  local shell_path

  if [ -x "$(volta_bin_path)" ]; then
    current_version="$(run_with_volta "volta --version" 2>/dev/null | head -n 1 || true)"
    if [ -n "$current_version" ]; then
      log "Volta 已安装：$current_version"
    else
      log "Volta 已安装"
    fi
  else
    log "Volta 未安装，开始安装"
  fi

  shell_path="$(target_login_shell)"
  if [ -z "$shell_path" ]; then
    shell_path="/bin/bash"
  fi

  run_as_target_user "export SHELL=$(shell_quote "$shell_path"); curl -fsSL https://get.volta.sh | bash" || return 1
  current_version="$(run_with_volta "volta --version" 2>/dev/null | head -n 1 || true)"
  if [ -n "$current_version" ]; then
    log "Volta 当前版本：$current_version"
  fi
}

ensure_node22_default() {
  local current_version

  current_version="$(run_with_volta "node -v" 2>/dev/null | tr -d '\r' || true)"

  if [ -n "$current_version" ]; then
    log "当前默认 Node：$current_version，执行 volta install node@22"
  else
    log "未检测到默认 Node，开始安装 Node 22"
  fi

  run_with_volta "volta install node@22" || return 1
  log "Node 当前版本：$(run_with_volta "node -v" 2>/dev/null | tr -d '\r')"
}

ensure_volta_package() {
  local package_spec="$1"
  local command_name="$2"
  local display_name="$3"
  local current_version

  if volta_command_exists "$command_name"; then
    current_version="$(volta_tool_version "$command_name")"
    if [ -n "$current_version" ]; then
      log "$display_name 已安装：$current_version"
    else
      log "$display_name 已安装"
    fi
  else
    log "$display_name 未安装，开始安装"
  fi

  run_with_volta "volta install $package_spec" || return 1

  current_version="$(volta_tool_version "$command_name")"
  if [ -n "$current_version" ]; then
    log "$display_name 当前版本：$current_version"
  else
    log "$display_name 安装完成"
  fi
}

prompt_auth_type() {
  while true; do
    read -r -p "认证类型 [password/digest]（默认：password）: " auth_type
    case "$auth_type" in
      ""|password|digest)
        printf '%s\n' "${auth_type:-password}"
        return 0
        ;;
      *)
        log "错误选项：$auth_type"
        ;;
    esac
  done
}

configure_ccman_sync() {
  local webdav_url
  local username
  local password
  local auth_type
  local remote_dir
  local sync_password
  local remember_flag="--remember-sync-password"
  local config_command

  if ! volta_command_exists "ccman"; then
    warn "ccman 未安装，跳过同步配置"
    return 1
  fi

  if ! prompt_yes_no_default_no "是否配置 ccman WebDAV 同步？"; then
    return 0
  fi

  webdav_url="$(prompt_with_default "输入 WebDAV 地址" "https://dav.example.com")"
  username="$(prompt_with_default "输入 WebDAV 用户名" "alice")"
  read -r -s -p "输入 WebDAV 密码: " password
  echo
  auth_type="$(prompt_auth_type)"
  remote_dir="$(prompt_with_default "输入远程同步目录" "/ccman")"
  read -r -s -p "输入同步加密密码: " sync_password
  echo

  if ! prompt_yes_no_default_yes "是否记住同步密码？"; then
    remember_flag="--forget-sync-password"
  fi

  config_command="ccman sync config \
    --webdav-url $(shell_quote "$webdav_url") \
    --username $(shell_quote "$username") \
    --password $(shell_quote "$password") \
    --auth-type $(shell_quote "$auth_type") \
    --remote-dir $(shell_quote "$remote_dir") \
    --sync-password $(shell_quote "$sync_password") \
    $remember_flag"

  run_with_volta "$config_command" || return 1

  if prompt_yes_no_default_yes "是否立即从 WebDAV 下载配置？"; then
    run_with_volta "ccman sync download --yes" || return 1
  fi
}

dev_toolchain() {
  print_section "安装/更新开发工具链"

  if ! target_command_exists curl; then
    warn "当前模块按官方方式使用 curl 安装 Volta，请先安装 curl"
    return 1
  fi

  ensure_volta_installed || return 1
  ensure_node22_default || return 1
  ensure_volta_package "ccman" "ccman" "ccman" || return 1
  ensure_volta_package "@openai/codex" "codex" "OpenAI Codex CLI" || return 1
  ensure_volta_package "@anthropic-ai/claude-code" "claude" "Claude Code" || return 1
  configure_ccman_sync || return 1

  log "开发工具链安装完成。如当前 shell 未立即生效，可执行 source ~/.zshrc 或重新打开终端。"
}

register_module "dev_toolchain" "dev_toolchain" "安装/更新 Volta、Node.js、ccman、Codex、Claude Code" "dev_toolchain"

DOCKER_KEYS=("code-server" "nginx" "pure-ftpd" "web_object_detection" "zfile" "subconverter" "sub-web" "mdserver-web" "qinglong" "webdav-client" "watchtower" "jsxm" "caddy" "codex2api" "sub2api")
DOCKER_INFOS=("在线 Web IDE" "Web 服务器" "FTP 服务器" "在线 web 目标识别" "在线云盘" "订阅转换后端" "订阅转换前端" "一款简单Linux面板服务" "定时任务管理面板" "Webdav 客户端，同步映射到宿主文件系统" "自动化更新 Docker 镜像和容器" "Web 在线 xm 音乐播放器" "Caddy 反向代理（域名反代到本地服务）" "Codex2API 一键部署（自动拉取 compose 和 env）" "Sub2API AI API 网关平台（订阅分发与管理）")

docker_stack_root() {
  printf '%s\n' "/root/docker-compose"
}

docker_stack_dir() {
  printf '%s/%s\n' "$(docker_stack_root)" "$1"
}

compose_file_path() {
  printf '%s/%s\n' "$(docker_stack_dir "$1")" "docker-compose.yml"
}

compose_env_path() {
  printf '%s/%s\n' "$(docker_stack_dir "$1")" ".env"
}

docker_service_stack_exists() {
  [ -f "$(compose_file_path "$1")" ]
}

run_service_compose() {
  local service_name="$1"
  local stack_dir
  local compose_path
  local env_path
  shift

  stack_dir="$(docker_stack_dir "$service_name")"
  compose_path="$(compose_file_path "$service_name")"
  env_path="$(compose_env_path "$service_name")"

  if [ ! -f "$compose_path" ]; then
    warn "未找到 ${service_name} 的 compose 文件：$compose_path"
    return 1
  fi

  if [ -f "$env_path" ]; then
    run_privileged docker compose --project-directory "$stack_dir" -f "$compose_path" --env-file "$env_path" "$@"
  else
    run_privileged docker compose --project-directory "$stack_dir" -f "$compose_path" "$@"
  fi
}

compose_service_names() {
  local compose_path="$1"

  awk '
    /^services:[[:space:]]*$/ {
      in_services = 1
      next
    }
    in_services && /^[^[:space:]]/ {
      exit
    }
    in_services && /^[[:space:]]{2}[A-Za-z0-9_.-]+:[[:space:]]*$/ {
      name = $1
      sub(/:$/, "", name)
      print name
    }
  ' "$compose_path"
}

docker_container_name_exists() {
  local container_name="$1"

  run_privileged docker ps -a --format '{{.Names}}' | grep -Fx -- "$container_name" >/dev/null 2>&1
}

compose_conflicting_container_names() {
  local compose_path="$1"
  local project_name="$2"
  local service_name
  local candidate

  while IFS= read -r service_name; do
    [ -n "$service_name" ] || continue
    for candidate in \
      "$service_name" \
      "${project_name}-${service_name}" \
      "${project_name}-${service_name}-1" \
      "${project_name}_${service_name}" \
      "${project_name}_${service_name}_1"
    do
      if docker_container_name_exists "$candidate"; then
        printf '%s\n' "$candidate"
      fi
    done
  done < <(compose_service_names "$compose_path")
}

dir_has_entries() {
  local dir_path="$1"

  [ -d "$dir_path" ] || return 1
  find "$dir_path" -mindepth 1 -maxdepth 1 -print -quit 2>/dev/null | grep -q .
}

docker_service_name_by_selection() {
  local selection="$1"

  if ! [[ "$selection" =~ ^[0-9]+$ ]]; then
    return 1
  fi

  printf '%s\n' "${DOCKER_KEYS[$selection]:-}"
}

generate_random_secret() {
  local length="${1:-32}"
  local secret=""

  while [ "${#secret}" -lt "$length" ]; do
    if command_exists openssl; then
      secret="${secret}$(openssl rand -base64 48 | tr -dc 'A-Za-z0-9' | head -c "$length" || true)"
    else
      secret="${secret}$(LC_ALL=C tr -dc 'A-Za-z0-9' </dev/urandom | head -c "$length" || true)"
    fi
  done

  printf '%s\n' "${secret:0:length}"
}

port_is_in_use() {
  local port="$1"
  local port_hex

  if command_exists ss; then
    ss -ltnH 2>/dev/null | awk '{print $4}' | grep -Eq "(:|\\])${port}$"
    return $?
  fi

  if command_exists lsof; then
    lsof -nP -iTCP:"$port" -sTCP:LISTEN >/dev/null 2>&1
    return $?
  fi

  if command_exists netstat; then
    netstat -ltn 2>/dev/null | awk '{print $4}' | grep -Eq "(:|\\])${port}$"
    return $?
  fi

  if [ -r /proc/net/tcp ] || [ -r /proc/net/tcp6 ]; then
    port_hex="$(printf '%04X' "$port")"
    awk -v port_hex="$port_hex" '
      $4 == "0A" {
        split($2, parts, ":")
        if (toupper(parts[2]) == port_hex) {
          found = 1
          exit
        }
      }
      END {
        exit !found
      }
    ' /proc/net/tcp /proc/net/tcp6 2>/dev/null
    return $?
  fi

  return 1
}

random_available_port() {
  local min_port="${1:-20000}"
  local max_port="${2:-59999}"
  local attempts="${3:-200}"
  local candidate
  local i

  for ((i = 0; i < attempts; i++)); do
    candidate=$((RANDOM % (max_port - min_port + 1) + min_port))
    if ! port_is_in_use "$candidate"; then
      printf '%s\n' "$candidate"
      return 0
    fi
  done

  for ((candidate = min_port; candidate <= max_port; candidate++)); do
    if ! port_is_in_use "$candidate"; then
      printf '%s\n' "$candidate"
      return 0
    fi
  done

  warn "未找到可用端口 (${min_port}-${max_port})"
  return 1
}

env_has_key() {
  local env_path="$1"
  local key="$2"

  [ -f "$env_path" ] || return 1
  grep -Eq "^[[:space:]]*${key}=" "$env_path"
}

env_get_value() {
  local env_path="$1"
  local key="$2"

  [ -f "$env_path" ] || return 1
  awk -F= -v key="$key" '
    BEGIN { found = 0 }
    $0 !~ /^[[:space:]]*#/ && $1 == key {
      found = 1
      sub(/^[^=]*=/, "", $0)
      print $0
      exit
    }
    END {
      if (!found) {
        exit 1
      }
    }
  ' "$env_path"
}

env_upsert_value() {
  local env_path="$1"
  local key="$2"
  local value="$3"
  local temp_file="${env_path}.tmp"

  awk -v key="$key" -v value="$value" '
    BEGIN { updated = 0 }
    $0 ~ "^[[:space:]]*" key "=" {
      print key "=" value
      updated = 1
      next
    }
    { print }
    END {
      if (!updated) {
        print key "=" value
      }
    }
  ' "$env_path" >"$temp_file"
  mv "$temp_file" "$env_path"
}

merge_env_defaults_from_template() {
  local env_path="$1"
  local template_path="$2"
  local line
  local key

  while IFS= read -r line; do
    case "$line" in
      ""|"#"*)
        continue
        ;;
      *=*)
        key="${line%%=*}"
        if ! env_has_key "$env_path" "$key"; then
          printf '\n%s\n' "$line" >>"$env_path"
        fi
        ;;
    esac
  done <"$template_path"
}

ensure_env_value() {
  local env_path="$1"
  local key="$2"
  local fallback="$3"
  local current_value

  current_value="$(env_get_value "$env_path" "$key" 2>/dev/null || true)"
  if [ -z "$current_value" ]; then
    env_upsert_value "$env_path" "$key" "$fallback"
  fi
}

env_value_or_default() {
  local env_path="$1"
  local key="$2"
  local fallback="$3"
  local current_value

  current_value="$(env_get_value "$env_path" "$key" 2>/dev/null || true)"
  if [ -z "$current_value" ]; then
    printf '%s\n' "$fallback"
  else
    printf '%s\n' "$current_value"
  fi
}

normalize_container_name() {
  local compose_file="$1"
  local container_name="$2"
  local temp_file

  temp_file="$(mktemp)"
  if grep -q '^[[:space:]]*container_name:' "$compose_file"; then
    run_privileged sed -i "s/^[[:space:]]*container_name:.*/    container_name: $container_name/" "$compose_file"
    rm -f "$temp_file"
    return 0
  fi

  awk -v name="$container_name" '
    !inserted && /^[[:space:]]*image:/ {
      print "    container_name: " name
      inserted=1
    }
    { print }
  ' "$compose_file" >"$temp_file" && run_privileged mv "$temp_file" "$compose_file"

  run_privileged chmod 644 "$compose_file"
  run_privileged chown root:root "$compose_file"
}

prepare_docker_compose() {
  local service_name="$1"
  local stack_dir
  local compose_path
  local temp_compose

  stack_dir="$(docker_stack_dir "$service_name")"
  compose_path="$(compose_file_path "$service_name")"
  ensure_privileged_dir "$(docker_stack_root)" "root"
  ensure_privileged_dir "$stack_dir" "root"

  if [ "$service_name" = "qinglong" ]; then
    temp_compose="$(mktemp)"
    download_to "https://$github_raw/whyour/qinglong/master/docker/docker-compose.yml" "$temp_compose" || {
      rm -f "$temp_compose"
      return 1
    }
    run_privileged mv "$temp_compose" "$compose_path"
    run_privileged chmod 644 "$compose_path"
    run_privileged chown root:root "$compose_path"
  else
    install_asset_file_privileged "docker/$service_name.yml" "$compose_path" "root" 644 || return 1
  fi

  normalize_container_name "$compose_path" "$service_name" || return 1
}

service_stack_file_path() {
  local service_name="$1"
  local relative_path="$2"

  printf '%s/%s\n' "$(docker_stack_dir "$service_name")" "$relative_path"
}

prepare_standard_service_stack_dirs() {
  local service_name="$1"
  local stack_dir
  local temp_file

  stack_dir="$(docker_stack_dir "$service_name")"
  ensure_privileged_dir "$(docker_stack_root)" "root"
  ensure_privileged_dir "$stack_dir" "root"

  case "$service_name" in
    code-server)
      ensure_privileged_dir "$(service_stack_file_path "$service_name" "config")" "root"
      ;;
    nginx)
      ensure_privileged_dir "$(service_stack_file_path "$service_name" "html")" "root"
      if [ ! -f "$(service_stack_file_path "$service_name" "html/index.html")" ]; then
        temp_file="$(mktemp)"
        cat >"$temp_file" <<'EOF'
<!doctype html>
<html lang="zh-CN">
  <head>
    <meta charset="utf-8" />
    <title>nginx</title>
  </head>
  <body>
    <h1>nginx is running</h1>
  </body>
</html>
EOF
        run_privileged mv "$temp_file" "$(service_stack_file_path "$service_name" "html/index.html")"
        run_privileged chmod 644 "$(service_stack_file_path "$service_name" "html/index.html")"
      fi
      ;;
    pure-ftpd)
      ensure_privileged_dir "$(service_stack_file_path "$service_name" "web_root")" "root"
      ensure_privileged_dir "$(service_stack_file_path "$service_name" "ftp_passwd")" "root"
      ;;
    zfile)
      ensure_privileged_dir "$(service_stack_file_path "$service_name" "zfile/db")" "root"
      ensure_privileged_dir "$(service_stack_file_path "$service_name" "zfile/logs")" "root"
      ensure_privileged_dir "$(service_stack_file_path "$service_name" "zfile/file")" "root"
      if [ ! -f "$(service_stack_file_path "$service_name" "application.properties")" ]; then
        run_privileged touch "$(service_stack_file_path "$service_name" "application.properties")"
        run_privileged chmod 644 "$(service_stack_file_path "$service_name" "application.properties")"
      fi
      ;;
  esac
}

show_docker_inventory() {
  echo
  log "已下载的 Docker 镜像:"
  run_privileged docker images -a
  echo
  log "已安装的 Docker 容器:"
  run_privileged docker ps -a
}

render_docker_menu() {
  local i

  for i in "${!DOCKER_KEYS[@]}"; do
    printf "%2s. %-20s%s\n" "$i" "${DOCKER_KEYS[$i]}" "${DOCKER_INFOS[$i]}"
  done
}

write_env_kv() {
  local env_path="$1"
  local temp_file
  shift

  temp_file="$(mktemp)"
  : >"$temp_file"
  while [ "$#" -gt 0 ]; do
    printf '%s\n' "$1" >>"$temp_file"
    shift
  done

  ensure_privileged_dir "$(dirname "$env_path")" "root"
  run_privileged mv "$temp_file" "$env_path"
  run_privileged chmod 600 "$env_path"
  run_privileged chown root:root "$env_path"
}

docker_init() {
  local docker_install_source

  print_section "安装/更新 Docker"

  docker_install_source="$(docker_install_source_preference 2>/dev/null || true)"
  case "$docker_install_source" in
    cn)
      run_remote_script "https://linuxmirrors.cn/docker.sh" || return 1
      ;;
    official)
      run_privileged mkdir -p /etc/apt/sources.list.d
      run_remote_script "https://get.docker.com" || return 1
      ;;
    *)
      while true; do
        read -r -p "是否配置国内源安装 docker? [Y/n] " input
        case "$input" in
          ""|[yY])
            run_remote_script "https://linuxmirrors.cn/docker.sh" || return 1
            break
            ;;
          [nN])
            run_privileged mkdir -p /etc/apt/sources.list.d
            run_remote_script "https://get.docker.com" || return 1
            break
            ;;
          *)
            log "错误选项：$input"
            ;;
        esac
      done
      ;;
  esac

  log "安装/更新 docker 环境完成!"
}

install_sub_web_assets() {
  local backend_address="$1"
  local repo_path
  local env_file

  repo_path="$(service_stack_file_path "sub-web" "sub-web")"
  env_file="$repo_path/.env"
  ensure_privileged_dir "$(docker_stack_dir "sub-web")" "root"
  if [ -d "$repo_path/.git" ]; then
    run_privileged git -C "$repo_path" pull --ff-only || return 1
  else
    run_privileged rm -rf "$repo_path"
    run_privileged git clone "https://$github_repo/CareyWang/sub-web" "$repo_path" || return 1
  fi

  if [ -f "$env_file" ]; then
    if grep -q '^VUE_APP_SUBCONVERTER_DEFAULT_BACKEND' "$env_file"; then
      run_privileged sed -i "s|^VUE_APP_SUBCONVERTER_DEFAULT_BACKEND.*|VUE_APP_SUBCONVERTER_DEFAULT_BACKEND = \"http://$backend_address\"|" "$env_file"
    else
      printf '%s\n' "VUE_APP_SUBCONVERTER_DEFAULT_BACKEND = \"http://$backend_address\"" | run_privileged tee -a "$env_file" >/dev/null
    fi
    run_privileged chown root:root "$env_file"
  fi
}

sub_web_current_backend() {
  local env_file
  local backend_value

  env_file="$(service_stack_file_path "sub-web" "sub-web/.env")"
  [ -f "$env_file" ] || return 1

  backend_value="$(awk '
    /^[[:space:]]*VUE_APP_SUBCONVERTER_DEFAULT_BACKEND[[:space:]]*=/ {
      sub(/^[^=]*=[[:space:]]*/, "", $0)
      gsub(/^["'"'"']|["'"'"']$/, "", $0)
      sub(/^https?:\/\//, "", $0)
      print
      exit
    }
  ' "$env_file")"

  [ -n "$backend_value" ] || return 1
  printf '%s\n' "$backend_value"
}

update_generic_docker_stack() {
  local service_name="$1"
  local current_backend

  if ! docker_service_stack_exists "$service_name"; then
    warn "未找到 ${service_name} 的部署目录：$(docker_stack_dir "$service_name")"
    return 1
  fi

  case "$service_name" in
    sub-web)
      current_backend="$(sub_web_current_backend 2>/dev/null || true)"
      install_sub_web_assets "${current_backend:-api.tsanfer.com:25500}" || return 1
      run_service_compose "$service_name" up -d --build || return 1
      ;;
    *)
      run_service_compose "$service_name" pull || return 1
      run_service_compose "$service_name" up -d || return 1
      ;;
  esac

  log "${service_name} 已更新，部署目录：$(docker_stack_dir "$service_name")"
}

remove_generic_docker_stack() {
  local service_name="$1"

  if docker_service_stack_exists "$service_name"; then
    run_service_compose "$service_name" down || return 1
    log "${service_name} 已停止并移除，部署目录仍保留：$(docker_stack_dir "$service_name")"
    return 0
  fi

  run_privileged docker rm -f "$service_name" 2>/dev/null || run_privileged docker stop "$service_name"
}

install_selected_docker() {
  local selection="$1"
  local service_name
  local compose_path
  local env_path
  local password
  local sudo_password
  local ftp_username
  local ftp_password
  local sub_web_backend
  local webdav_url
  local webdav_user
  local webdav_pass
  local webdav_local_path
  local update_interval

  service_name="$(docker_service_name_by_selection "$selection" 2>/dev/null || true)"
  if [ -z "$service_name" ]; then
    log "错误选项：$selection"
    return 1
  fi

  if [ "$service_name" = "codex2api" ]; then
    install_codex2api_stack
    return $?
  fi

  if [ "$service_name" = "sub2api" ]; then
    install_sub2api_stack
    return $?
  fi

  if [ "$service_name" = "caddy" ]; then
    install_caddy_stack
    return $?
  fi

  compose_path="$(compose_file_path "$service_name")"
  env_path="$(compose_env_path "$service_name")"
  prepare_docker_compose "$service_name" || return 1
  prepare_standard_service_stack_dirs "$service_name"

  case "$selection" in
    0)
      read -r -s -p "设置密码: " password
      echo
      read -r -s -p "设置 sudo 密码: " sudo_password
      echo
      write_env_kv "$env_path" "PASSWORD=$password" "SUDO_PASSWORD=$sudo_password"
      run_service_compose "$service_name" up -d
      ;;
    1|3|4|5|7|8|11)
      run_service_compose "$service_name" up -d
      ;;
    2)
      read -r -p "设置 ftp 用户名: " ftp_username
      read -r -s -p "设置 ftp 密码: " ftp_password
      echo
      write_env_kv "$env_path" "FTP_USER_NAME=$ftp_username" "FTP_USER_PASS=$ftp_password"
      run_service_compose "$service_name" up -d
      ;;
    6)
      sub_web_backend="$(prompt_with_default "设置订阅转换后端地址" "api.tsanfer.com:25500")"
      install_sub_web_assets "$sub_web_backend" || return 1
      run_service_compose "$service_name" up -d
      ;;
    9)
      webdav_url="$(prompt_with_default "输入 webdav 服务器地址(url)" "https://dav.jianguoyun.com/dav/我的坚果云")"
      webdav_user="$(prompt_with_default "输入 webdav 用户名" "a1124851454@gmail.com")"
      read -r -s -p "输入 webdav 密码: " webdav_pass
      echo
      webdav_local_path="$(prompt_with_default "输入 webdav 本地目录" "/mnt/webdav")"
      write_env_kv "$env_path" \
        "WEBDRIVE_URL=$webdav_url" \
        "WEBDRIVE_USERNAME=$webdav_user" \
        "WEBDRIVE_PASSWORD=$webdav_pass" \
        "WEBDRIVE_LOCAL_PATH=$webdav_local_path"
      run_service_compose "$service_name" up -d
      ;;
    10)
      update_interval="$(prompt_with_default "设置 Docker 镜像检查更新频率，单位：秒" "30")"
      write_env_kv "$env_path" "INTERVAL=$update_interval"
      run_service_compose "$service_name" up -d
      ;;
  esac
}

docker_install() {
  print_section "从 Docker compose 部署 docker 容器"
  log "检查 Docker 状态..."

  if ! command_exists docker; then
    warn "Docker 未安装!"
    return 1
  fi

  while true; do
    echo
    log "已安装的 Docker 容器:"
    run_privileged docker ps -a
    render_docker_menu
    read -r -p "选择需要安装的 Docker 容器序号 (q:退出): " input

    case "$input" in
      [qQ])
        break
        ;;
      *)
        install_selected_docker "$input"
        ;;
    esac
  done

  show_docker_inventory
}

docker_update() {
  print_section "更新 docker 镜像和容器"
  log "检查 Docker 状态..."

  if ! command_exists docker; then
    warn "Docker 未安装!"
    return 1
  fi

  echo
  log "已安装的 Docker 容器:"
  run_privileged docker ps -a

  while true; do
    local service_name

    render_docker_menu
    read -r -p "选择需要更新的 Docker 容器序号 (q:退出): " input

    service_name="$(docker_service_name_by_selection "$input" 2>/dev/null || true)"
    case "$input" in
      [qQ])
        break
        ;;
    esac

    case "$service_name" in
      caddy)
        update_caddy_stack
        ;;
      codex2api)
        update_codex2api_stack
        ;;
      sub2api)
        update_sub2api_stack
        ;;
      "")
        log "错误选项：$input"
        ;;
      *)
        update_generic_docker_stack "$service_name"
        ;;
    esac
  done

  show_docker_inventory
}

docker_remove() {
  local service_name

  print_section "删除 docker 镜像和容器"
  log "检查 Docker 状态..."

  if ! command_exists docker; then
    warn "Docker 未安装!"
    return 1
  fi

  echo
  log "已安装的 Docker 容器:"
  run_privileged docker ps -a

  while true; do
    local service_name

    render_docker_menu
    read -r -p "选择需要删除的 Docker 容器序号 (q:退出): " input

    service_name="$(docker_service_name_by_selection "$input" 2>/dev/null || true)"
    case "$input" in
      [qQ])
        break
        ;;
    esac

    case "$service_name" in
      codex2api)
        remove_codex2api_stack
        ;;
      sub2api)
        remove_sub2api_stack
        ;;
      "")
        log "错误选项：$input"
        ;;
      *)
        remove_generic_docker_stack "$service_name"
        ;;
    esac
  done

  if prompt_yes_no_default_no "是否同时清理未使用的 Docker 镜像和缓存"; then
    run_privileged docker system prune -a -f
  fi
  show_docker_inventory
}

register_module "docker_init" "docker_init" "安装，更新 Docker" "docker_init"
register_module "docker_install" "docker_install" "从 Docker compose 部署 docker 容器" "docker_install"
register_module "docker_update" "docker_update" "更新 docker 镜像和容器" "docker_update"
register_module "docker_remove" "docker_remove" "删除 docker 镜像和容器" "docker_remove"

caddy_stack_dir() {
  docker_stack_dir "caddy"
}

caddyfile_path() {
  printf '%s/%s\n' "$(caddy_stack_dir)" "Caddyfile"
}

caddy_data_dir() {
  printf '%s/%s\n' "$(caddy_stack_dir)" "data"
}

caddy_config_dir() {
  printf '%s/%s\n' "$(caddy_stack_dir)" "config"
}

caddy_logs_dir() {
  printf '%s/%s\n' "$(caddy_data_dir)" "logs"
}

caddy_current_profile() {
  local caddyfile="$1"

  [ -f "$caddyfile" ] || return 1
  awk -F': ' '
    /^#[[:space:]]*setup-server-caddy-profile:/ {
      print $2
      exit
    }
  ' "$caddyfile"
}

caddy_current_domain() {
  local caddyfile="$1"

  [ -f "$caddyfile" ] || return 1
  awk '
    /^[[:space:]]*$/ { next }
    /^[[:space:]]*#/ { next }
    /^[[:space:]]*\{/ { next }
    /^[[:space:]]*\}/ { next }
    {
      gsub(/[[:space:]]*\{[[:space:]]*$/, "", $0)
      gsub(/^[[:space:]]+|[[:space:]]+$/, "", $0)
      print
      exit
    }
  ' "$caddyfile"
}

caddy_current_upstream() {
  local caddyfile="$1"

  [ -f "$caddyfile" ] || return 1
  awk '
    $1 == "reverse_proxy" {
      print $2
      exit
    }
  ' "$caddyfile"
}

prepare_caddy_stack_dirs() {
  ensure_privileged_dir "$(docker_stack_root)" "root"
  ensure_privileged_dir "$(caddy_stack_dir)" "root"
  ensure_privileged_dir "$(caddy_data_dir)" "root"
  ensure_privileged_dir "$(caddy_config_dir)" "root"
  ensure_privileged_dir "$(caddy_logs_dir)" "root"
}

caddy_default_sub2api_upstream() {
  local env_path
  local sub2api_port

  env_path="$(sub2api_env_path 2>/dev/null || true)"
  if [ -n "$env_path" ] && [ -f "$env_path" ]; then
    sub2api_port="$(env_value_or_default "$env_path" "SERVER_PORT" "8080")"
  else
    sub2api_port="8080"
  fi

  printf 'host.docker.internal:%s\n' "$sub2api_port"
}

caddy_sub2api_request_body_limit() {
  local env_path
  local gateway_bytes
  local server_bytes
  local max_bytes

  env_path="$(sub2api_env_path 2>/dev/null || true)"
  gateway_bytes="268435456"
  server_bytes="268435456"

  if [ -n "$env_path" ] && [ -f "$env_path" ]; then
    gateway_bytes="$(env_value_or_default "$env_path" "GATEWAY_MAX_BODY_SIZE" "$gateway_bytes")"
    server_bytes="$(env_value_or_default "$env_path" "SERVER_MAX_REQUEST_BODY_SIZE" "$server_bytes")"
  fi

  if ! [[ "$gateway_bytes" =~ ^[0-9]+$ ]]; then
    gateway_bytes="268435456"
  fi
  if ! [[ "$server_bytes" =~ ^[0-9]+$ ]]; then
    server_bytes="268435456"
  fi

  if [ "$gateway_bytes" -ge "$server_bytes" ]; then
    max_bytes="$gateway_bytes"
  else
    max_bytes="$server_bytes"
  fi

  if [ "$max_bytes" -gt 0 ] && [ $((max_bytes % 1048576)) -eq 0 ]; then
    printf '%sMB\n' "$((max_bytes / 1048576))"
  else
    printf '%s\n' "$max_bytes"
  fi
}

configure_caddy_reverse_proxy() {
  local caddyfile
  local temp_file
  local default_domain
  local default_upstream
  local domain_name
  local upstream_target

  caddyfile="$(caddyfile_path)"
  temp_file="$(mktemp)"
  default_domain="$(caddy_current_domain "$caddyfile" 2>/dev/null || true)"
  default_upstream="$(caddy_current_upstream "$caddyfile" 2>/dev/null || true)"

  if [ -z "$default_domain" ]; then
    default_domain="example.com"
  fi
  if [ -z "$default_upstream" ]; then
    default_upstream="host.docker.internal:3000"
  fi

  domain_name="$(prompt_with_default "输入需要反向代理的域名" "$default_domain")"
  while [ -z "$domain_name" ]; do
    warn "域名不能为空"
    domain_name="$(prompt_with_default "输入需要反向代理的域名" "$default_domain")"
  done

  upstream_target="$(prompt_with_default "输入本地服务地址（host:port）" "$default_upstream")"
  while [ -z "$upstream_target" ]; do
    warn "本地服务地址不能为空"
    upstream_target="$(prompt_with_default "输入本地服务地址（host:port）" "$default_upstream")"
  done

  cat >"$temp_file" <<EOF
# setup-server-caddy-profile: generic
$domain_name {
    encode zstd gzip
    reverse_proxy $upstream_target
}
EOF
  run_privileged mv "$temp_file" "$caddyfile"
  run_privileged chmod 644 "$caddyfile"
  run_privileged chown root:root "$caddyfile"

  log "Caddy 配置已写入：$caddyfile"
  log "域名：$domain_name"
  log "反代到：$upstream_target"
}

configure_caddy_sub2api_reverse_proxy() {
  local caddyfile
  local temp_file
  local default_domain
  local default_upstream
  local domain_name
  local upstream_target
  local request_body_limit

  caddyfile="$(caddyfile_path)"
  temp_file="$(mktemp)"
  default_domain="$(caddy_current_domain "$caddyfile" 2>/dev/null || true)"
  default_upstream="$(caddy_current_upstream "$caddyfile" 2>/dev/null || true)"
  request_body_limit="$(caddy_sub2api_request_body_limit)"

  if [ -z "$default_domain" ]; then
    default_domain="api.example.com"
  fi
  if [ -z "$default_upstream" ]; then
    default_upstream="$(caddy_default_sub2api_upstream)"
  fi

  domain_name="$(prompt_with_default "输入 sub2api 对外域名" "$default_domain")"
  while [ -z "$domain_name" ]; do
    warn "域名不能为空"
    domain_name="$(prompt_with_default "输入 sub2api 对外域名" "$default_domain")"
  done

  upstream_target="$(prompt_with_default "输入 sub2api 上游地址（host:port）" "$default_upstream")"
  while [ -z "$upstream_target" ]; do
    warn "上游地址不能为空"
    upstream_target="$(prompt_with_default "输入 sub2api 上游地址（host:port）" "$default_upstream")"
  done

  cat >"$temp_file" <<EOF
# setup-server-caddy-profile: sub2api
$domain_name {
    @static {
        path /assets/*
        path /logo.png
        path /favicon.ico
    }
    header @static {
        Cache-Control "public, max-age=31536000, immutable"
        -Pragma
        -Expires
    }

    tls {
        protocols tls1.2 tls1.3
        ciphers TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384 TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384 TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305_SHA256 TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305_SHA256 TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256 TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256
    }

    reverse_proxy $upstream_target {
        health_uri /health
        health_interval 30s
        health_timeout 10s
        health_status 200

        lb_policy round_robin
        lb_try_duration 5s
        lb_try_interval 250ms

        header_up X-Real-IP {remote_host}
        header_up CF-Connecting-IP {http.request.header.CF-Connecting-IP}

        transport http {
            keepalive 120s
            keepalive_idle_conns 256
            read_buffer 16KB
            write_buffer 16KB
            compression off
        }

        fail_duration 30s
        max_fails 3
        unhealthy_status 500 502 503 504
    }

    encode {
        zstd
        gzip 6
        minimum_length 256
        match {
            header Content-Type text/*
            header Content-Type application/json*
            header Content-Type application/javascript*
            header Content-Type application/xml*
            header Content-Type application/rss+xml*
            header Content-Type image/svg+xml*
        }
    }

    request_body {
        max_size $request_body_limit
    }

    log {
        output file /data/logs/sub2api-access.log {
            roll_size 50mb
            roll_keep 10
            roll_keep_for 720h
        }
        format json
        level INFO
    }

    handle_errors {
        respond "{err.status_code} {err.status_text}"
    }
}
EOF
  run_privileged mv "$temp_file" "$caddyfile"
  run_privileged chmod 644 "$caddyfile"
  run_privileged chown root:root "$caddyfile"

  log "Sub2API 适配版 Caddy 配置已写入：$caddyfile"
  log "域名：$domain_name"
  log "反代到：$upstream_target"
  log "请求体限制：$request_body_limit"
}

configure_caddy_profile() {
  local current_profile="${1:-}"

  if [ "$current_profile" = "sub2api" ]; then
    if prompt_yes_no_default_yes "是否使用适配 sub2api 的 Caddy 配置模板？"; then
      configure_caddy_sub2api_reverse_proxy
    else
      configure_caddy_reverse_proxy
    fi
    return $?
  fi

  if prompt_yes_no_default_no "是否使用适配 sub2api 的 Caddy 配置模板？"; then
    configure_caddy_sub2api_reverse_proxy
  else
    configure_caddy_reverse_proxy
  fi
}

install_caddy_stack() {
  local compose_path
  local current_domain

  compose_path="$(compose_file_path "caddy")"
  prepare_docker_compose "caddy" || return 1
  prepare_caddy_stack_dirs
  configure_caddy_profile "" || return 1

  run_service_compose "caddy" up -d || return 1
  current_domain="$(caddy_current_domain "$(caddyfile_path)" 2>/dev/null || true)"
  log "Caddy 已部署。"
  if [ -n "$current_domain" ]; then
    log "请确保域名已解析到当前服务器：$current_domain"
  fi
  log "80/443 端口需要对外放行，且不应被其他服务占用。"
}

update_caddy_stack() {
  local compose_path
  local current_profile

  compose_path="$(compose_file_path "caddy")"
  prepare_docker_compose "caddy" || return 1
  prepare_caddy_stack_dirs
  current_profile="$(caddy_current_profile "$(caddyfile_path)" 2>/dev/null || true)"

  if [ ! -f "$(caddyfile_path)" ]; then
    configure_caddy_profile "$current_profile" || return 1
  elif prompt_yes_no_default_no "是否同时更新 Caddy 反向代理配置？"; then
    configure_caddy_profile "$current_profile" || return 1
  fi

  run_service_compose "caddy" pull || return 1
  run_service_compose "caddy" up -d || return 1
  log "Caddy 已更新。"
}

codex2api_stack_dir() {
  docker_stack_dir "codex2api"
}

codex2api_compose_path() {
  printf '%s/%s\n' "$(codex2api_stack_dir)" "docker-compose.yml"
}

codex2api_env_path() {
  printf '%s/%s\n' "$(codex2api_stack_dir)" ".env"
}

codex2api_env_example_path() {
  printf '%s/%s\n' "$(codex2api_stack_dir)" ".env.example"
}

codex2api_install_info_path() {
  printf '%s/%s\n' "$(codex2api_stack_dir)" "INSTALL_INFO.txt"
}

codex2api_stack_exists() {
  [ -f "$(codex2api_compose_path)" ] && [ -f "$(codex2api_env_path)" ]
}

codex2api_admin_secret_needs_generation() {
  case "$1" in
    ""|"changeme"|"your-admin-password"|"your_admin_secret"|"your-secure-admin-password-here")
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

codex2api_database_password_needs_generation() {
  case "$1" in
    ""|"codex2api"|"changeme"|"your_db_password"|"your-strong-db-password")
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

resolve_stack_bind_path() {
  local stack_dir="$1"
  local bind_path="$2"

  case "$bind_path" in
    /*)
      printf '%s\n' "$bind_path"
      ;;
    ./*)
      printf '%s/%s\n' "$stack_dir" "${bind_path#./}"
      ;;
    *)
      printf '%s/%s\n' "$stack_dir" "$bind_path"
      ;;
  esac
}

codex2api_prepare_stack_dirs() {
  local stack_dir="$1"
  local env_path="$2"
  local postgres_dir
  local redis_dir
  local logs_dir

  postgres_dir="$(resolve_stack_bind_path "$stack_dir" "$(env_value_or_default "$env_path" "POSTGRES_DATA_DIR" "./data/codex2api-postgres")")"
  redis_dir="$(resolve_stack_bind_path "$stack_dir" "$(env_value_or_default "$env_path" "REDIS_DATA_DIR" "./data/codex2api-redis")")"
  logs_dir="$(resolve_stack_bind_path "$stack_dir" "$(env_value_or_default "$env_path" "LOGS_DIR" "./logs")")"

  ensure_privileged_dir "$postgres_dir" "root"
  ensure_privileged_dir "$redis_dir" "root"
  ensure_privileged_dir "$logs_dir" "root"
}

codex2api_postgres_data_dir() {
  local stack_dir="$1"
  local env_path="${2:-}"

  if [ -n "$env_path" ] && [ -f "$env_path" ]; then
    resolve_stack_bind_path "$stack_dir" "$(env_value_or_default "$env_path" "POSTGRES_DATA_DIR" "./data/codex2api-postgres")"
  else
    printf '%s/%s\n' "$stack_dir" "data/codex2api-postgres"
  fi
}

codex2api_has_existing_postgres_data() {
  local stack_dir="$1"
  local env_path="${2:-}"
  local postgres_dir

  postgres_dir="$(codex2api_postgres_data_dir "$stack_dir" "$env_path")"
  [ -f "$postgres_dir/PG_VERSION" ] || dir_has_entries "$postgres_dir"
}

codex2api_run_compose() {
  local stack_dir="$1"
  local compose_command="$2"

  run_privileged bash -lc "cd $(shell_quote "$stack_dir") && $compose_command"
}

codex2api_sync_remote_files() {
  local repo_owner="$1"
  local repo_ref="$2"
  local stack_dir
  local compose_path
  local env_path
  local env_example_path
  local temp_compose
  local temp_env
  local compose_url
  local env_url

  stack_dir="$(codex2api_stack_dir)"
  compose_path="$(codex2api_compose_path)"
  env_path="$(codex2api_env_path)"
  env_example_path="$(codex2api_env_example_path)"
  temp_compose="$(mktemp)"
  temp_env="$(mktemp)"
  compose_url="https://$github_raw/$repo_owner/codex2api/$repo_ref/docker-compose.yml"
  env_url="https://$github_raw/$repo_owner/codex2api/$repo_ref/.env.example"

  ensure_privileged_dir "$(docker_stack_root)" "root"
  ensure_privileged_dir "$stack_dir" "root"

  download_to "$compose_url" "$temp_compose" || {
    rm -f "$temp_compose" "$temp_env"
    return 1
  }
  download_to "$env_url" "$temp_env" || {
    rm -f "$temp_compose" "$temp_env"
    return 1
  }

  run_privileged mv "$temp_compose" "$compose_path"
  run_privileged mv "$temp_env" "$env_example_path"
  run_privileged chmod 644 "$compose_path" "$env_example_path"
  run_privileged chown root:root "$compose_path" "$env_example_path"

  if [ ! -f "$env_path" ]; then
    run_privileged cp "$env_example_path" "$env_path"
  else
    merge_env_defaults_from_template "$env_path" "$env_example_path"
  fi

  run_privileged chmod 600 "$env_path"
  run_privileged chown root:root "$env_path"
}

codex2api_collect_settings() {
  local env_path="$1"
  local repo_owner
  local repo_ref
  local ghcr_owner
  local image_tag
  local project_name
  local codex_port
  local admin_secret
  local database_password

  repo_owner="$(env_value_or_default "$env_path" "SETUP_SERVER_REPO_OWNER" "yyssp")"
  repo_ref="$(env_value_or_default "$env_path" "SETUP_SERVER_REPO_REF" "main")"
  ghcr_owner="$(env_value_or_default "$env_path" "GHCR_OWNER" "$repo_owner")"
  image_tag="$(env_value_or_default "$env_path" "CODEX_IMAGE_TAG" "latest")"
  project_name="$(env_value_or_default "$env_path" "COMPOSE_PROJECT_NAME" "codex2api")"

  if ! prompt_yes_no_default_yes "使用默认/当前 codex2api 部署参数"; then
    repo_owner="$(prompt_with_default "设置 codex2api 仓库 owner" "$repo_owner")"
    repo_ref="$(prompt_with_default "设置 codex2api 仓库分支或 tag" "$repo_ref")"
    ghcr_owner="$(prompt_with_default "设置 GHCR 镜像 owner" "$ghcr_owner")"
    image_tag="$(prompt_with_default "设置镜像 tag" "$image_tag")"
    project_name="$(prompt_with_default "设置 Compose 项目标识" "$project_name")"
  fi

  while true; do
    read -r -p "设置 codex2api 访问端口（回车自动分配空闲端口）: " codex_port
    if [ -z "$codex_port" ]; then
      break
    fi
    if ! [[ "$codex_port" =~ ^[0-9]+$ ]] || [ "$codex_port" -lt 1 ] || [ "$codex_port" -gt 65535 ]; then
      warn "端口无效：$codex_port，请重新输入"
      continue
    fi
    if port_is_in_use "$codex_port"; then
      warn "端口已被占用：$codex_port，请重新输入"
      continue
    fi
    break
  done

  read -r -s -p "设置 ADMIN_SECRET（回车自动生成）: " admin_secret
  echo
  read -r -s -p "设置数据库密码（回车自动生成）: " database_password
  echo

  printf '%s\n' "$repo_owner|$repo_ref|$ghcr_owner|$image_tag|$project_name|$codex_port|$admin_secret|$database_password"
}

codex2api_configure_env() {
  local env_path="$1"
  local repo_owner="$2"
  local repo_ref="$3"
  local ghcr_owner="$4"
  local image_tag="$5"
  local project_name="$6"
  local codex_port="$7"
  local admin_secret_override="${8:-}"
  local database_password_override="${9:-}"
  local fresh_install="${10:-0}"
  local admin_secret
  local database_password

  env_upsert_value "$env_path" "SETUP_SERVER_REPO_OWNER" "$repo_owner"
  env_upsert_value "$env_path" "SETUP_SERVER_REPO_REF" "$repo_ref"
  env_upsert_value "$env_path" "GHCR_OWNER" "$ghcr_owner"
  env_upsert_value "$env_path" "CODEX_IMAGE_TAG" "$image_tag"
  env_upsert_value "$env_path" "COMPOSE_PROJECT_NAME" "$project_name"
  env_upsert_value "$env_path" "CODEX_PORT" "$codex_port"

  ensure_env_value "$env_path" "POSTGRES_DATA_DIR" "./data/codex2api-postgres"
  ensure_env_value "$env_path" "REDIS_DATA_DIR" "./data/codex2api-redis"
  ensure_env_value "$env_path" "LOGS_DIR" "./logs"
  ensure_env_value "$env_path" "DATABASE_DRIVER" "postgres"
  ensure_env_value "$env_path" "DATABASE_HOST" "codex2api-postgres"
  ensure_env_value "$env_path" "DATABASE_PORT" "5432"
  ensure_env_value "$env_path" "DATABASE_USER" "codex2api"
  ensure_env_value "$env_path" "DATABASE_NAME" "codex2api"
  ensure_env_value "$env_path" "CACHE_DRIVER" "redis"
  ensure_env_value "$env_path" "REDIS_ADDR" "codex2api-redis:6379"
  ensure_env_value "$env_path" "REDIS_DB" "0"
  ensure_env_value "$env_path" "TZ" "Asia/Shanghai"

  if [ -n "$admin_secret_override" ]; then
    env_upsert_value "$env_path" "ADMIN_SECRET" "$admin_secret_override"
  fi
  admin_secret="$(env_get_value "$env_path" "ADMIN_SECRET" 2>/dev/null || true)"
  if [ "$fresh_install" = "1" ] && codex2api_admin_secret_needs_generation "$admin_secret"; then
    env_upsert_value "$env_path" "ADMIN_SECRET" "$(generate_random_secret 24)"
  elif [ -z "$admin_secret" ]; then
    env_upsert_value "$env_path" "ADMIN_SECRET" "$(generate_random_secret 24)"
  fi

  if [ -n "$database_password_override" ]; then
    env_upsert_value "$env_path" "DATABASE_PASSWORD" "$database_password_override"
  fi
  database_password="$(env_get_value "$env_path" "DATABASE_PASSWORD" 2>/dev/null || true)"
  if [ "$fresh_install" = "1" ] && codex2api_database_password_needs_generation "$database_password"; then
    env_upsert_value "$env_path" "DATABASE_PASSWORD" "$(generate_random_secret 24)"
  elif [ -z "$database_password" ]; then
    env_upsert_value "$env_path" "DATABASE_PASSWORD" "$(generate_random_secret 24)"
  fi

  run_privileged chmod 600 "$env_path"
  run_privileged chown root:root "$env_path"
}

codex2api_write_install_info() {
  local stack_dir="$1"
  local env_path="$2"
  local codex_port="$3"
  local info_path
  local admin_secret
  local database_password
  local temp_file

  info_path="$(codex2api_install_info_path)"
  admin_secret="$(env_get_value "$env_path" "ADMIN_SECRET" 2>/dev/null || true)"
  database_password="$(env_get_value "$env_path" "DATABASE_PASSWORD" 2>/dev/null || true)"
  temp_file="$(mktemp)"

  cat >"$temp_file" <<EOF
codex2api 部署信息

部署目录: $stack_dir
访问地址: http://localhost:$codex_port
管理后台: http://localhost:$codex_port/admin/

ADMIN_SECRET=$admin_secret
DATABASE_PASSWORD=$database_password
EOF

  run_privileged mv "$temp_file" "$info_path"
  run_privileged chmod 600 "$info_path"
  run_privileged chown root:root "$info_path"
}

install_codex2api_stack() {
  local stack_dir
  local compose_path
  local env_path
  local settings
  local repo_owner
  local repo_ref
  local ghcr_owner
  local image_tag
  local project_name
  local codex_port
  local admin_secret
  local database_password
  local conflict_names

  stack_dir="$(codex2api_stack_dir)"
  compose_path="$(codex2api_compose_path)"
  env_path="$(codex2api_env_path)"
  ensure_privileged_dir "$(docker_stack_root)" "root"
  ensure_privileged_dir "$stack_dir" "root"

  if codex2api_stack_exists; then
    warn "codex2api 已存在：$stack_dir"
    log "请使用“更新 docker 镜像和容器”来刷新现有服务。"
    log "当前访问地址：http://localhost:$(env_value_or_default "$env_path" "CODEX_PORT" "8080")"
    return 0
  fi

  if codex2api_has_existing_postgres_data "$stack_dir"; then
    warn "检测到已存在的 PostgreSQL 数据目录：$(codex2api_postgres_data_dir "$stack_dir")"
    warn "这通常表示之前部署过 codex2api，但只清掉了 compose 文件或容器，没有清掉数据目录。"
    warn "PostgreSQL 只会在首次初始化时读取 DATABASE_PASSWORD；当前继续安装会导致数据库密码与 .env 不一致。"
    log "如需保留旧数据，请恢复原 .env 后执行“更新 docker 镜像和容器”。"
    log "如无需保留旧数据，请先删除目录后再重装：$(codex2api_postgres_data_dir "$stack_dir")"
    return 1
  fi

  settings="$(codex2api_collect_settings "$env_path")" || return 1
  IFS='|' read -r repo_owner repo_ref ghcr_owner image_tag project_name codex_port admin_secret database_password <<<"$settings"
  if [ -z "$codex_port" ]; then
    codex_port="$(random_available_port)" || return 1
  fi

  codex2api_sync_remote_files "$repo_owner" "$repo_ref" || return 1
  conflict_names="$(compose_conflicting_container_names "$compose_path" "$project_name" 2>/dev/null | sort -u)"
  if [ -n "$conflict_names" ]; then
    warn "检测到已存在的同名容器，已停止安装："
    printf '%s\n' "$conflict_names" >&2
    warn "请先清理这些容器，或修改 COMPOSE_PROJECT_NAME 后再安装。"
    return 1
  fi
  codex2api_configure_env "$env_path" "$repo_owner" "$repo_ref" "$ghcr_owner" "$image_tag" "$project_name" "$codex_port" "$admin_secret" "$database_password" "1"
  codex2api_prepare_stack_dirs "$stack_dir" "$env_path"

  codex2api_run_compose "$stack_dir" "docker compose pull && docker compose up -d" || return 1
  codex2api_write_install_info "$stack_dir" "$env_path" "$codex_port"
  log "codex2api 已部署，配置目录：$stack_dir"
  log "访问地址：http://localhost:$codex_port"
  log "管理后台：http://localhost:$codex_port/admin/"
  log "ADMIN_SECRET: $(env_get_value "$env_path" "ADMIN_SECRET" 2>/dev/null || true)"
  log "数据库密码和管理后台密钥已写入：$env_path"
  log "安装信息文件：$(codex2api_install_info_path)"
}

update_codex2api_stack() {
  local stack_dir
  local env_path
  local repo_owner
  local repo_ref
  local codex_port

  stack_dir="$(codex2api_stack_dir)"
  env_path="$(codex2api_env_path)"

  if [ ! -f "$env_path" ]; then
    warn "未找到 codex2api 的部署目录：$stack_dir"
    return 1
  fi

  repo_owner="$(env_value_or_default "$env_path" "SETUP_SERVER_REPO_OWNER" "yyssp")"
  repo_ref="$(env_value_or_default "$env_path" "SETUP_SERVER_REPO_REF" "main")"
  codex_port="$(env_value_or_default "$env_path" "CODEX_PORT" "")"
  if [ -z "$codex_port" ] || port_is_in_use "$codex_port"; then
    codex_port="$(random_available_port)" || return 1
  fi

  codex2api_sync_remote_files "$repo_owner" "$repo_ref" || return 1
  codex2api_configure_env \
    "$env_path" \
    "$repo_owner" \
    "$repo_ref" \
    "$(env_value_or_default "$env_path" "GHCR_OWNER" "$repo_owner")" \
    "$(env_value_or_default "$env_path" "CODEX_IMAGE_TAG" "latest")" \
    "$(env_value_or_default "$env_path" "COMPOSE_PROJECT_NAME" "codex2api")" \
    "$codex_port" \
    "" \
    "" \
    "0"
  codex2api_prepare_stack_dirs "$stack_dir" "$env_path"

  codex2api_run_compose "$stack_dir" "docker compose pull && docker compose up -d" || return 1
  codex2api_write_install_info "$stack_dir" "$env_path" "$codex_port"
  log "codex2api 已更新，配置目录：$stack_dir"
  log "访问地址：http://localhost:$codex_port"
  log "安装信息文件：$(codex2api_install_info_path)"
}

remove_codex2api_stack() {
  local stack_dir

  stack_dir="$(codex2api_stack_dir)"

  if [ ! -f "$(codex2api_compose_path)" ]; then
    warn "未找到 codex2api 的部署目录：$stack_dir"
    return 1
  fi

  codex2api_run_compose "$stack_dir" "docker compose down" || return 1
  log "codex2api 容器已停止并移除，数据目录仍保留：$stack_dir"
}

sub2api_stack_dir() {
  docker_stack_dir "sub2api"
}

sub2api_compose_path() {
  printf '%s/%s\n' "$(sub2api_stack_dir)" "docker-compose.yml"
}

sub2api_env_path() {
  printf '%s/%s\n' "$(sub2api_stack_dir)" ".env"
}

sub2api_env_example_path() {
  printf '%s/%s\n' "$(sub2api_stack_dir)" ".env.example"
}

sub2api_install_info_path() {
  printf '%s/%s\n' "$(sub2api_stack_dir)" "INSTALL_INFO.txt"
}

sub2api_stack_exists() {
  [ -f "$(sub2api_compose_path)" ] && [ -f "$(sub2api_env_path)" ]
}

sub2api_has_existing_stack_files() {
  [ -f "$(sub2api_compose_path)" ] \
    || [ -f "$(sub2api_env_path)" ] \
    || [ -f "$(sub2api_env_example_path)" ] \
    || [ -f "$(sub2api_install_info_path)" ]
}

sub2api_existing_data_dirs() {
  local stack_dir="$1"
  local dir_path

  for dir_path in \
    "$stack_dir/data" \
    "$stack_dir/postgres_data" \
    "$stack_dir/redis_data"
  do
    if [ -f "$dir_path/PG_VERSION" ] || dir_has_entries "$dir_path"; then
      printf '%s\n' "$dir_path"
    fi
  done
}

sub2api_postgres_password_needs_generation() {
  case "$1" in
    ""|"change_this_secure_password"|"changeme"|"your_password"|"your-strong-password")
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

sub2api_generate_random_email() {
  local random_part
  random_part="$(generate_random_secret 8 | tr 'A-Z' 'a-z')"
  printf 'admin_%s@sub2api.local\n' "$random_part"
}

sub2api_sync_remote_files() {
  local repo_owner="$1"
  local repo_ref="$2"
  local stack_dir
  local compose_path
  local env_path
  local env_example_path
  local temp_compose
  local temp_env
  local compose_url
  local env_url

  stack_dir="$(sub2api_stack_dir)"
  compose_path="$(sub2api_compose_path)"
  env_path="$(sub2api_env_path)"
  env_example_path="$(sub2api_env_example_path)"
  temp_compose="$(mktemp)"
  temp_env="$(mktemp)"
  compose_url="https://$github_raw/$repo_owner/sub2api/$repo_ref/deploy/docker-compose.local.yml"
  env_url="https://$github_raw/$repo_owner/sub2api/$repo_ref/deploy/.env.example"

  ensure_privileged_dir "$(docker_stack_root)" "root"
  ensure_privileged_dir "$stack_dir" "root"

  download_to "$compose_url" "$temp_compose" || {
    rm -f "$temp_compose" "$temp_env"
    return 1
  }
  download_to "$env_url" "$temp_env" || {
    rm -f "$temp_compose" "$temp_env"
    return 1
  }

  run_privileged mv "$temp_compose" "$compose_path"
  run_privileged mv "$temp_env" "$env_example_path"
  run_privileged chmod 644 "$compose_path" "$env_example_path"
  run_privileged chown root:root "$compose_path" "$env_example_path"

  if [ ! -f "$env_path" ]; then
    run_privileged cp "$env_example_path" "$env_path"
  else
    merge_env_defaults_from_template "$env_path" "$env_example_path"
  fi

  run_privileged chmod 600 "$env_path"
  run_privileged chown root:root "$env_path"
}

sub2api_collect_settings() {
  local env_path="$1"
  local repo_owner
  local repo_ref
  local sub2api_port
  local admin_email
  local admin_password

  repo_owner="$(env_value_or_default "$env_path" "SETUP_SERVER_REPO_OWNER" "Wei-Shaw")"
  repo_ref="$(env_value_or_default "$env_path" "SETUP_SERVER_REPO_REF" "main")"

  if ! prompt_yes_no_default_yes "使用默认/当前 sub2api 部署参数"; then
    repo_owner="$(prompt_with_default "设置 sub2api 仓库 owner" "$repo_owner")"
    repo_ref="$(prompt_with_default "设置 sub2api 仓库分支或 tag" "$repo_ref")"
  fi

  while true; do
    read -r -p "设置 sub2api 访问端口（回车自动分配空闲端口）: " sub2api_port
    if [ -z "$sub2api_port" ]; then
      break
    fi
    if ! [[ "$sub2api_port" =~ ^[0-9]+$ ]] || [ "$sub2api_port" -lt 1 ] || [ "$sub2api_port" -gt 65535 ]; then
      warn "端口无效：$sub2api_port，请重新输入"
      continue
    fi
    if port_is_in_use "$sub2api_port"; then
      warn "端口已被占用：$sub2api_port，请重新输入"
      continue
    fi
    break
  done

  read -r -p "设置管理员邮箱（回车随机生成）: " admin_email
  read -r -s -p "设置管理员密码（回车随机生成）: " admin_password
  echo

  printf '%s\n' "$repo_owner|$repo_ref|$sub2api_port|$admin_email|$admin_password"
}

sub2api_configure_env() {
  local env_path="$1"
  local repo_owner="$2"
  local repo_ref="$3"
  local sub2api_port="$4"
  local admin_email="${5:-}"
  local admin_password="${6:-}"
  local fresh_install="${7:-0}"
  local postgres_password
  local jwt_secret
  local totp_key

  env_upsert_value "$env_path" "SETUP_SERVER_REPO_OWNER" "$repo_owner"
  env_upsert_value "$env_path" "SETUP_SERVER_REPO_REF" "$repo_ref"
  env_upsert_value "$env_path" "SERVER_PORT" "$sub2api_port"
  ensure_env_value "$env_path" "TZ" "Asia/Shanghai"

  if [ -n "$admin_email" ]; then
    env_upsert_value "$env_path" "ADMIN_EMAIL" "$admin_email"
  elif [ "$fresh_install" = "1" ]; then
    env_upsert_value "$env_path" "ADMIN_EMAIL" "$(sub2api_generate_random_email)"
  fi

  if [ -n "$admin_password" ]; then
    env_upsert_value "$env_path" "ADMIN_PASSWORD" "$admin_password"
  elif [ "$fresh_install" = "1" ]; then
    env_upsert_value "$env_path" "ADMIN_PASSWORD" "$(generate_random_secret 16)"
  fi

  postgres_password="$(env_get_value "$env_path" "POSTGRES_PASSWORD" 2>/dev/null || true)"
  if [ "$fresh_install" = "1" ] && sub2api_postgres_password_needs_generation "$postgres_password"; then
    env_upsert_value "$env_path" "POSTGRES_PASSWORD" "$(generate_random_secret 24)"
  elif [ -z "$postgres_password" ]; then
    env_upsert_value "$env_path" "POSTGRES_PASSWORD" "$(generate_random_secret 24)"
  fi

  jwt_secret="$(env_get_value "$env_path" "JWT_SECRET" 2>/dev/null || true)"
  if [ -z "$jwt_secret" ]; then
    env_upsert_value "$env_path" "JWT_SECRET" "$(generate_random_secret 64)"
  fi

  totp_key="$(env_get_value "$env_path" "TOTP_ENCRYPTION_KEY" 2>/dev/null || true)"
  if [ -z "$totp_key" ]; then
    env_upsert_value "$env_path" "TOTP_ENCRYPTION_KEY" "$(generate_random_secret 64)"
  fi

  run_privileged chmod 600 "$env_path"
  run_privileged chown root:root "$env_path"
}

sub2api_prepare_stack_dirs() {
  local stack_dir="$1"

  ensure_privileged_dir "$stack_dir/data" "root"
  ensure_privileged_dir "$stack_dir/postgres_data" "root"
  ensure_privileged_dir "$stack_dir/redis_data" "root"
}

sub2api_write_install_info() {
  local stack_dir="$1"
  local env_path="$2"
  local sub2api_port="$3"
  local info_path
  local admin_email
  local admin_password
  local postgres_password
  local jwt_secret
  local totp_key
  local temp_file

  info_path="$(sub2api_install_info_path)"
  admin_email="$(env_get_value "$env_path" "ADMIN_EMAIL" 2>/dev/null || true)"
  admin_password="$(env_get_value "$env_path" "ADMIN_PASSWORD" 2>/dev/null || true)"
  postgres_password="$(env_get_value "$env_path" "POSTGRES_PASSWORD" 2>/dev/null || true)"
  jwt_secret="$(env_get_value "$env_path" "JWT_SECRET" 2>/dev/null || true)"
  totp_key="$(env_get_value "$env_path" "TOTP_ENCRYPTION_KEY" 2>/dev/null || true)"
  temp_file="$(mktemp)"

  cat >"$temp_file" <<EOF
sub2api 部署信息

部署目录: $stack_dir
访问地址: http://localhost:$sub2api_port

ADMIN_EMAIL=$admin_email
ADMIN_PASSWORD=$admin_password
POSTGRES_PASSWORD=$postgres_password
JWT_SECRET=$jwt_secret
TOTP_ENCRYPTION_KEY=$totp_key
EOF

  run_privileged mv "$temp_file" "$info_path"
  run_privileged chmod 600 "$info_path"
  run_privileged chown root:root "$info_path"
}

install_sub2api_stack() {
  local stack_dir
  local compose_path
  local env_path
  local settings
  local repo_owner
  local repo_ref
  local sub2api_port
  local admin_email
  local admin_password
  local conflict_names
  local existing_data_dirs

  stack_dir="$(sub2api_stack_dir)"
  compose_path="$(sub2api_compose_path)"
  env_path="$(sub2api_env_path)"
  ensure_privileged_dir "$(docker_stack_root)" "root"
  ensure_privileged_dir "$stack_dir" "root"

  if sub2api_stack_exists; then
    warn "sub2api 已存在：$stack_dir"
    log "请使用“更新 docker 镜像和容器”来刷新现有服务。"
    log "当前访问地址：http://localhost:$(env_value_or_default "$env_path" "SERVER_PORT" "8080")"
    return 0
  fi

  if sub2api_has_existing_stack_files; then
    warn "检测到已有 sub2api 部署文件：$stack_dir"
    log "为避免覆盖现有 compose/.env 文件，安装已停止。"
    log "如为现有部署，请改用“更新 docker 镜像和容器”；如需重装，请先清理 $stack_dir 下的部署文件。"
    return 1
  fi

  existing_data_dirs="$(sub2api_existing_data_dirs "$stack_dir" | sort -u)"
  if [ -n "$existing_data_dirs" ]; then
    warn "检测到已存在的数据目录，可能之前已经部署过 sub2api："
    printf '%s\n' "$existing_data_dirs" >&2
    warn "继续安装可能导致新 .env 与旧数据不一致。"
    log "如需保留旧数据，请恢复原 .env 后执行“更新 docker 镜像和容器”。"
    log "如无需保留旧数据，请先清理上述目录后再重装。"
    return 1
  fi

  settings="$(sub2api_collect_settings "$env_path")" || return 1
  IFS='|' read -r repo_owner repo_ref sub2api_port admin_email admin_password <<<"$settings"
  if [ -z "$sub2api_port" ]; then
    sub2api_port="$(random_available_port)" || return 1
  fi

  sub2api_sync_remote_files "$repo_owner" "$repo_ref" || return 1
  conflict_names="$(compose_conflicting_container_names "$compose_path" "sub2api" 2>/dev/null | sort -u)"
  if [ -n "$conflict_names" ]; then
    warn "检测到已存在的同名容器，已停止安装："
    printf '%s\n' "$conflict_names" >&2
    warn "请先清理这些容器后再安装。"
    return 1
  fi
  sub2api_configure_env "$env_path" "$repo_owner" "$repo_ref" "$sub2api_port" "$admin_email" "$admin_password" "1"
  sub2api_prepare_stack_dirs "$stack_dir"

  run_service_compose "sub2api" pull || return 1
  run_service_compose "sub2api" up -d || return 1
  sub2api_write_install_info "$stack_dir" "$env_path" "$sub2api_port"
  log "sub2api 已部署，配置目录：$stack_dir"
  log "访问地址：http://localhost:$sub2api_port"
  log "管理员邮箱：$(env_get_value "$env_path" "ADMIN_EMAIL" 2>/dev/null || true)"
  log "管理员密码：$(env_get_value "$env_path" "ADMIN_PASSWORD" 2>/dev/null || true)"
  log "数据库密码、JWT_SECRET、TOTP_ENCRYPTION_KEY 等已写入：$env_path"
  log "安装信息文件：$(sub2api_install_info_path)"
}

update_sub2api_stack() {
  local stack_dir
  local env_path
  local repo_owner
  local repo_ref
  local sub2api_port

  stack_dir="$(sub2api_stack_dir)"
  env_path="$(sub2api_env_path)"

  if [ ! -f "$env_path" ]; then
    warn "未找到 sub2api 的部署目录：$stack_dir"
    return 1
  fi

  repo_owner="$(env_value_or_default "$env_path" "SETUP_SERVER_REPO_OWNER" "Wei-Shaw")"
  repo_ref="$(env_value_or_default "$env_path" "SETUP_SERVER_REPO_REF" "main")"
  sub2api_port="$(env_value_or_default "$env_path" "SERVER_PORT" "")"

  if [ -z "$sub2api_port" ] || ! [[ "$sub2api_port" =~ ^[0-9]+$ ]] || [ "$sub2api_port" -lt 1 ] || [ "$sub2api_port" -gt 65535 ]; then
    sub2api_port="$(random_available_port)" || return 1
  fi

  sub2api_sync_remote_files "$repo_owner" "$repo_ref" || return 1
  sub2api_configure_env "$env_path" "$repo_owner" "$repo_ref" "$sub2api_port" "" "" "0"
  sub2api_prepare_stack_dirs "$stack_dir"

  run_service_compose "sub2api" pull || return 1
  run_service_compose "sub2api" up -d || return 1
  sub2api_write_install_info "$stack_dir" "$env_path" "$sub2api_port"
  log "sub2api 已更新，配置目录：$stack_dir"
  log "访问地址：http://localhost:$sub2api_port"
  log "安装信息文件：$(sub2api_install_info_path)"
}

remove_sub2api_stack() {
  local stack_dir

  stack_dir="$(sub2api_stack_dir)"

  if [ ! -f "$(sub2api_compose_path)" ]; then
    warn "未找到 sub2api 的部署目录：$stack_dir"
    return 1
  fi

  run_service_compose "sub2api" down || return 1
  log "sub2api 容器已停止并移除，数据目录仍保留：$stack_dir"
}

change_timezone() {
  local timezones=("Asia/Shanghai" "America/New_York" "Europe/London" "Australia/Sydney")
  local chosen_timezone

  print_section "调整时区"
  echo "请选择要设置的时区（或直接输入时区名称）："
  select chosen_timezone in "${timezones[@]}" "输入其他时区"; do
    case "$chosen_timezone" in
      "输入其他时区")
        read -r -p "请输入时区名称：" NEW_TIMEZONE
        break
        ;;
      "")
        log "错误选项：$REPLY"
        ;;
      *)
        NEW_TIMEZONE="$chosen_timezone"
        break
        ;;
    esac
  done

  if ! command_exists timedatectl; then
    warn "timedatectl 命令未找到。请确保已安装 systemd。"
    return 1
  fi

  run_privileged timedatectl set-timezone "$NEW_TIMEZONE"
  log "时区已设置为 $NEW_TIMEZONE"
}

apt_clean() {
  print_section "清理 APT 空间"

  if prompt_yes_no_default_yes "是否清理 APT 空间？"; then
    run_privileged apt clean -y || return 1
    run_privileged apt autoclean -y || return 1
    run_privileged apt autoremove --purge -y || return 1
  fi
}

sys_reboot() {
  print_section "重启系统"

  if prompt_yes_no_default_yes "是否重启系统？"; then
    run_privileged reboot
  fi
}

register_module "change_timezone" "change_timezone" "调整时区" "change_timezone"
register_module "apt_clean" "apt_clean" "清理 APT 空间" "apt_clean"
register_module "sys_reboot" "sys_reboot" "重启系统" "sys_reboot"

INIT_FLOW=("app_update_init" "swap_set" "vps_reviews" "term_config" "docker_init" "app_install" "docker_install" "change_timezone" "apt_clean" "sys_reboot")

run_init_flow() {
  local module_id

  for module_id in "${INIT_FLOW[@]}"; do
    run_module "$module_id" || return 1
  done
}

show_main_menu() {
  local i
  local module_id

  echo
  log "选择要运行的脚本:"
  print_divider
  for i in "${!MODULE_IDS[@]}"; do
    module_id="${MODULE_IDS[$i]}"
    printf "|%2s.|%-20s|%-s|\n" "$((i + 1))" "${MODULE_TITLES[$i]}" "${MODULE_DESCRIPTIONS[$i]}"
    print_divider
  done
  log "i. 初始化配置脚本"
  print_divider
}

main() {
  local input
  local index
  local module_id

  ensure_supported_os || return 1
  init_runtime
  github_proxy_set

  while true; do
    show_main_menu
    read -r -p "选择要进行的操作 (q:退出): " input

    case "$input" in
      [iI])
        run_init_flow || warn "初始化流程已中断"
        ;;
      [qQ])
        break
        ;;
      *)
        if [[ "$input" =~ ^[0-9]+$ ]]; then
          index=$((input - 1))
          if (( index >= 0 && index < ${#MODULE_IDS[@]} )); then
            module_id="${MODULE_IDS[$index]}"
            run_module "$module_id"
          else
            log "错误选项：$input"
          fi
        else
          log "错误选项：$input"
        fi
        ;;
    esac
  done

  log "Done!!!"
}

main "$@"
